const rawContent = $input.item.json.message.content;
let qcResults;
try {
  qcResults = JSON.parse(rawContent);
} catch(e) {
  const match = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try { qcResults = JSON.parse(match[1]); } catch(e2) { throw new Error('Could not parse QC output: ' + e2.message); }
  } else {
    throw new Error('Could not parse QC output: ' + e.message);
  }
}
const items = [];
for (const item of qcResults) {
  items.push({
    json: {
      ...item,
      is_approved: item.approval_status === 'APPROVED',
      run_date: new Date().toISOString().split('T')[0]
    }
  });
}
return items;
